        ["options_use_uniqueids"]           = "РҳСҒРҝРҫР»СҢР·РҫРІР°СӮСҢ СғРҪРёРәР°Р»СҢРҪСӢР№ ID",
        ["options_use_uniqueids_TT"]   = "Р’РәР»СҺСҮРөРҪРҫ:\nРҳСҒРҝРҫР»СҢР·СғРөСӮСҒСҸ СғРҪРёРәР°Р»СҢРҪСӢР№ ID РҝСҖРөРҙРјРөСӮР°.\n\nРӯСӮРҫ РҝРҫР·РІРҫР»РёСӮ Р’Р°Рј РҝРҫРјРөСҮР°СӮСҢ СҖР°Р·РҪСӢРјРё РҝРҫРјРөСӮРәР°РјРё РҫРҙРёРҪР°РәРҫРІРҫ РІСӢРіР»СҸРҙСҸСүРёРө РҝСҖРөРҙРјРөСӮСӢ, РҪРҫ СҖР°Р·Р»РёСҮР°СҺСүРёРөСҒСҸ Р·Р°СҮР°СҖРҫРІР°РҪРёРөРј/СҒСӮРёР»РөРј/СғСҖРҫРІРҪРөРј Рё СӮ.Рҝ.\n\n\&#1042;СӢРәР»СҺСҮРөРҪРҫ:\nРҳСҒРҝРҫР»СҢР·СғРөСӮСҒСҸ РҫРұСӢСҮРҪСӢР№ ID Рё РҝСҖРөРҙРјРөСӮСӢ РІСӢРіР»СҸРҙСҸСүРёРө РҫРҙРёРҪР°РәРҫРІРҫ РҝРҫРјРөСҮР°СҺСӮСҒСҸ РІСҒРө СҒСҖР°Р·Сғ.\n\nР’РҪРёРјР°РҪРёРө: РҹРҫРјРөСӮРәРё, СғР¶Рө СғСҒСӮР°РҪРҫРІР»РөРҪРҪСӢРө РҪР° Р’Р°СҲРёС… РҝСҖРөРҙРјРөСӮР°С…, РұСғРҙСғСӮ СҒРҫС…СҖР°РҪРөРҪСӢ РёСҒРҝРҫР»СҢР·СғРөРјСӢРј РјРөСӮРҫРҙРҫРј СҒРҫС…СҖР°РҪРөРҪРёСҸ. РҹРөСҖРөРәР»СҺСҮРөРҪРёРө СҖРөР¶РёРјР° СҒРҪРҫРІР° РҝРҫРәР°Р¶РөСӮ РІР°Рј СҒРҫС…СҖР°РҪРөРҪРҪСӢРө РҝРҫРјРөСӮРәРё!\n\nР”Р»СҸ РёР·РјРөРҪРөРҪРёСҸ СҚСӮРҫРіРҫ РҝР°СҖР°РјРөСӮСҖР° Р’Р°Рј РҪСғР¶РҪРҫ РІСҖСғСҮРҪСғСҺ РҝРөСҖРөР·Р°РіСҖСғР·РёСӮСҢ РҝРҫР»СҢР·РҫРІР°СӮРөР»СҢСҒРәРёР№ РёРҪСӮРөСҖС„РөР№СҒ!",
        ["options_migrate_uniqueids"]           = "РҹРөСҖРөРҪРөСҒСӮРё РҝРҫРјРөСӮРәРё",
