        elseif language == FCOIS_CON_LANG_JP then
            translatedTexts[FCOIS_CON_LANG_JP][LF_FENCE_SELL] 			= "зӣ—йӣЈе•Ҷе“ҒгҒ®иіје…ҘиҖ… " .. GetString(SI_ITEM_ACTION_SELL)
            translatedTexts[FCOIS_CON_LANG_JP][LF_FENCE_LAUNDER]		= "зӣ—йӣЈе•Ҷе“ҒгҒ®иіје…ҘиҖ… " .. GetString(SI_FENCE_LAUNDER_TAB)
        --Russian
        elseif language == FCOIS_CON_LANG_RU then
            translatedTexts[FCOIS_CON_LANG_RU][LF_FENCE_SELL] 			= "СҒРәСғРҝСүРёРә РәСҖР°РҙРөРҪРҫРіРҫ " .. GetString(SI_ITEM_ACTION_SELL)
            translatedTexts[FCOIS_CON_LANG_RU][LF_FENCE_LAUNDER]		= "СҒРәСғРҝСүРёРә РәСҖР°РҙРөРҪРҫРіРҫ " .. GetString(SI_FENCE_LAUNDER_TAB)
        end
    end
    --Return whole table of a language, or only one filter panel data?
    if libFilterPanelId == nil then
        retVarTable = translatedTexts[language]
    else
        --Only return one filter panel data
        retVarTable = translatedTexts[language][libFilterPanelId]
    end
    return retVarTable
end
